#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Node {
    char *key;
    long long val;
    struct Node *next;
} Node;

#define TABLE_SIZE 200003 // a prime larger than expected distinct keys

unsigned long hash(const char *s) {
    unsigned long h = 0;
    while (*s) {
        h = h * 131 + (unsigned char)*s++;
    }
    return h % TABLE_SIZE;
}

Node *table[TABLE_SIZE];

Node* findNode(const char *key) {
    unsigned long idx = hash(key);
    Node *cur = table[idx];
    while (cur) {
        if (strcmp(cur->key, key) == 0) return cur;
        cur = cur->next;
    }
    return NULL;
}

void add(const char *key, long long val) {
    Node *node = findNode(key);
    if (node) {
        node->val += val;
        return;
    }
    unsigned long idx = hash(key);
    node = (Node*)malloc(sizeof(Node));
    node->key = strdup(key);
    node->val = val;
    node->next = table[idx];
    table[idx] = node;
}

int cmp_ll(const void *a, const void *b) {
    long long x = *(const long long*)a;
    long long y = *(const long long*)b;
    return (x > y) - (x < y);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        // clear hash table
        for (int i=0;i<TABLE_SIZE;i++) {
            Node *cur = table[i];
            while (cur) {
                Node *tmp = cur; cur = cur->next; free(tmp->key); free(tmp);
            }
            table[i]=NULL;
        }
        char code[16]; long long cnt;
        for (int i=0;i<3*N;i++) {
            scanf("%s %lld", code, &cnt);
            add(code, cnt);
        }
        // collect values
        long long *vals = (long long*)malloc(sizeof(long long)*3*N);
        int p=0;
        for (int i=0;i<TABLE_SIZE;i++) {
            Node *cur = table[i];
            while (cur) {
                vals[p++] = cur->val;
                cur = cur->next;
            }
        }
        qsort(vals, p, sizeof(long long), cmp_ll);
        for (int i=0;i<p;i++) {
            if (i) printf(" ");
            printf("%lld", vals[i]);
        }
        printf("\n");
        free(vals);
    }
    return 0;
}

