import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            HashMap<String, Long> map = new HashMap<>(3 * N * 2);
            for (int i = 0; i < 3 * N; i++) {
                String code = fs.next();
                long cnt = fs.nextLong();
                map.put(code, map.getOrDefault(code, 0L) + cnt);
            }
            long[] arr = new long[map.size()];
            int idx = 0;
            for (long v : map.values()) arr[idx++] = v;
            Arrays.sort(arr);
            for (int i = 0; i < arr.length; i++) {
                if (i > 0) out.append(' ');
                out.append(arr[i]);
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
    // Fast scanner for whitespace‑separated tokens
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is) { in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        private boolean isSpace(int c) { return c <= ' '; }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && isSpace(c));
            while (c != -1 && !isSpace(c)) {
                sb.append((char) c);
                c = readByte();
            }
            return sb.toString();
        }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        long nextLong() throws IOException { return Long.parseLong(next()); }
    }
}

