#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        mp = {}
        for _ in range(3 * N):
            code = next(it)
            cnt = int(next(it))
            mp[code] = mp.get(code, 0) + cnt
        vals = sorted(mp.values())
        out_lines.append(' '.join(map(str, vals)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

